import "./styles/Login.css";
import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../api/axios";

function Login() {
  const navigate = useNavigate();

  const genres = [
    "Fantasy",
    "Fiction",
    "Literature",
    "Business",
    "Technology",
    "SelfHelp",
    "History",
    "Biography",
    "Philosophy",
    "Psychology",
    "Science",
    "Romance",
    "Mystery",
    "Horror",
    "Motivation",
    "Finance"
  ];

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Student");
  const [genre, setGenre] = useState("");
  const [error, setError] = useState("");

  // 🔐 Prevent login page if already logged in
  useEffect(() => {
    const isLoggedIn = localStorage.getItem("isLoggedIn");
    const savedRole = localStorage.getItem("role");

    if (isLoggedIn === "true") {
      if (savedRole === "Student") {
        navigate("/student-dashboard", { replace: true });
      } else if (savedRole === "Librarian") {
        navigate("/librarian-dashboard", { replace: true });
      } else if (savedRole === "Admin") {
        navigate("/admin-dashboard", { replace: true });
      }
    }
  }, [navigate]);

  const handleLogin = async () => {
    try {
      setError("");

      if (role === "Librarian" && !genre) {
        return setError("Please select your genre");
      }

      const res = await api.post("/auth/login", {
        email,
        password,
        role,
        genre: role === "Librarian" ? genre : undefined
      });

      const { _id, name, role: userRole, genre: userGenre } = res.data;

      // 🔥 Save login state
      localStorage.setItem("isLoggedIn", "true");
      localStorage.setItem("userId", _id);
      localStorage.setItem("userName", name);
      localStorage.setItem("role", userRole);

      if (userRole === "Librarian") {
        localStorage.setItem("genre", userGenre);
      }

      // 🔁 Redirect
      if (userRole === "Student") {
        navigate("/student-dashboard", { replace: true });
      } else if (userRole === "Librarian") {
        navigate("/librarian-dashboard", { replace: true });
      } else if (userRole === "Admin") {
        navigate("/admin-dashboard", { replace: true });
      }

    } catch (err) {
      setError(err.response?.data?.message || "Invalid login credentials");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <h2>Login</h2>

        {error && <p className="error">{error}</p>}

        <input
          type="email"
          placeholder="University Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select value={role} onChange={(e) => setRole(e.target.value)}>
          <option>Student</option>
          <option>Librarian</option>
          <option>Admin</option>
        </select>

        {/* 🔥 Genre Dropdown Only for Librarian */}
        {role === "Librarian" && (
          <select value={genre} onChange={(e) => setGenre(e.target.value)}>
            <option value="">Select Your Genre</option>
            {genres.map((g) => (
              <option key={g} value={g}>
                {g}
              </option>
            ))}
          </select>
        )}

        <button className="login-btn" onClick={handleLogin}>
          Login
        </button>
      </div>
    </div>
  );
}

export default Login;
